import java.util.function.*;
public class Predicates {
    public static void main(String[] args) {
        Predicate<Integer> isEven = n -> n % 2 == 0;
        Predicate<Integer> isPos = n -> n > 0;
        Predicate<Integer> both = isEven.and(isPos);
        Predicate<Integer> either = isEven.or(isPos);
        System.out.println(both.test(4));
        System.out.println(both.test(-4));
        System.out.println(either.test(-3));
        System.out.println(isEven.negate().test(3));
    }
}
